🔴 *Error:* {{ $json.execution.error.message }}
📍 *Failed node:* {{ $json.execution.lastNodeExecuted }}
🆔 *Execution ID:* {{ $json.execution.id }}
🔗 *Execution URL:* https://n8n.pi.alex-it.net/executions/{{ $json.execution.id }}
🕐 *Time:* {{ $now.setZone('Asia/Jerusalem').toFormat('yyyy-MM-dd HH:mm') }}

=✅ *PI Workflows Backup Complete*

📁 *Folder:* `{{ $('Create README Text').item.json.folderName }}`
🔢 *Workflows backed up:* {{ $('Create README Text').item.json.workflowCount }}
🔗 *GitHub:* {{ $('Create README Text').item.json.ghUrl }}
💾 *Google Drive:* Backed up to `My Drive/{{ $('Create README Text').item.json.folderName }}`
🕐 *Time:* {{ $now.setZone('Asia/Jerusalem').toFormat('yyyy-MM-dd HH:mm') }}

parameters.jsCode:
const dt = $now.setZone('Asia/Jerusalem');
const folderName = `PI workflows backup ${dt.toFormat('yyyy-MM-dd HH-mm')}`;
const timestamp = dt.toFormat('yyyy-MM-dd HH:mm');

return $items().map((item) => {
  const json = item.json || {};
  const bin  = item.binary || {};
  const data = bin.data || {};

  const orig = (data.fileName || (json.name ? json.name + '.json' : 'workflow.json')).toString();
  const safe = orig.replace(/[\/\\]+/g, '-').replace(/\s+/g, ' ').trim();

  bin.data = Object.assign({}, data, { fileName: safe });
  json.workflowName = json.name || safe.replace('.json', '');
  json.folderName = folderName;
  json.timestamp = timestamp;

  return { json, binary: bin };
});

const name = $json.name || 'workflow-backup';
const filename = name + '.json';
const fileContent = JSON.stringify($json, null, 2);

return {
  json: { name: name },
  binary: {
    data: {
      data: Buffer.from(fileContent).toString('base64'),
      mimeType: 'application/json',
      fileName: filename
    }
  }
};

const allItems = $items('Normalize Filename1') || [];

const folderName = allItems[0]?.json?.folderName || 'PI workflows backup';
const timestamp  = allItems[0]?.json?.timestamp  || $now.setZone('Asia/Jerusalem').toFormat('yyyy-MM-dd HH:mm');

const workflowNames = allItems.map(i => i.json?.workflowName).filter(Boolean);

const OWNER  = 'alexxx55555';
const REPO   = 'n8n-Raspberry-PI-Workflow-Backup';
const BRANCH = 'main';

const encodedFolder = encodeURIComponent(folderName);
const ghUrl = `https://github.com/${OWNER}/${REPO}/tree/${BRANCH}/${encodedFolder}`;

const readme = `# n8n-Raspberry-PI-Workflow-Backup

## Latest Backup: ${timestamp}

### Backup URL
${ghUrl}

### Workflows Backed Up (${workflowNames.length} total)
${workflowNames.length ? workflowNames.map(n => `- ${n}`).join('\n') : '- (no workflows found)'}

---
*Backup generated automatically by n8n*`;

return [{ json: { readme, timestamp, folderName, ghUrl, workflowCount: workflowNames.length } }];

const text = ($json.readme || '# PI workflows backup\n\n(empty)').replace(/\r?\n/g, '\n');

// ✅ Fixed: correctly references 'GitHub Get README1'
const getReadmeItem = $item(0, 'GitHub Get README');
const sha = getReadmeItem?.json?.sha || '';

return {
  json: { sha },
  binary: {
    data: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      fileName: 'README.md',
      mimeType: 'text/markdown'
    }
  }
};

const folders = $items()
  .filter(i => i.json?.type === 'dir' && i.json?.name?.startsWith('PI workflows backup '))
  .map(i => ({ name: i.json.name, path: i.json.path }));

if (folders.length <= 1) return [];

const parseDate = (name) => {
  const match = name.match(/(\d{4}-\d{2}-\d{2}) (\d{2})-(\d{2})$/);
  if (!match) return new Date('1900-01-01');
  try { return new Date(`${match[1]}T${match[2]}:${match[3]}:00`); }
  catch { return new Date('1900-01-01'); }
};

const sorted = folders
  .map(f => ({ ...f, date: parseDate(f.name) }))
  .sort((a, b) => b.date - a.date);

return sorted.slice(1).map(f => ({ json: { path: f.path, name: f.name } }));

